-- Tables (raw + derived). Order among plain tables is free (no cross-refs).
CREATE TABLE IF NOT EXISTS price_data.account_activity (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `event_name` LowCardinality(String), `block_timestamp` DateTime, `is_module_transfer` UInt8) ENGINE = ReplacingMergeTree PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account, block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_activity_v3 (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `event_name` LowCardinality(String), `block_timestamp` DateTime, `is_module_transfer` UInt8, `asset_id` UInt32, `amount` UInt256, `has_amount` UInt8) ENGINE = ReplacingMergeTree PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account, block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_asset_latest_balances (`account_id` String, `asset_id` String, `total_state` AggregateFunction(argMax, Nullable(String), UInt32), `free_state` AggregateFunction(argMax, Nullable(String), UInt32), `reserved_state` AggregateFunction(argMax, Nullable(String), UInt32), `last_block_state` AggregateFunction(max, UInt32)) ENGINE = AggregatingMergeTree ORDER BY (account_id, asset_id) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_asset_latest_nonzero_balances (`account_id` String, `asset_id` String, `total_state` AggregateFunction(argMax, Nullable(String), UInt32), `last_block_state` AggregateFunction(max, UInt32)) ENGINE = AggregatingMergeTree ORDER BY (asset_id, account_id) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_balance_history (`account_id` String, `asset_id` String, `asset_kind` LowCardinality(String), `block_height` UInt32, `block_timestamp` DateTime, `observation_id` String, `total` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account_id, asset_id, block_height, asset_kind, observation_id) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.account_balance_hourly (`account_id` String, `asset_id` String, `interval_start` DateTime, `balance_state` AggregateFunction(argMax, String, Tuple(UInt32, String, DateTime)), `block_state` AggregateFunction(argMax, UInt32, Tuple(UInt32, String, DateTime)), `first_block_state` AggregateFunction(min, UInt32), `last_block_state` AggregateFunction(max, UInt32), `first_timestamp_state` AggregateFunction(min, DateTime), `last_timestamp_state` AggregateFunction(max, DateTime)) ENGINE = AggregatingMergeTree PARTITION BY toYear(interval_start) ORDER BY (account_id, asset_id, interval_start) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.account_balance_weekly (`account_id` String, `asset_id` String, `week_start` Date, `balance_state` AggregateFunction(argMax, String, Tuple(UInt32, UInt32, String, DateTime)), `activity_state` AggregateFunction(uniq, Tuple(UInt32, Nullable(UInt32))), `last_block_state` AggregateFunction(max, UInt32)) ENGINE = AggregatingMergeTree PARTITION BY toYear(week_start) ORDER BY (account_id, asset_id, week_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_directory_snapshots (`snapshot_key` String, `payload_json` String, `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) ORDER BY snapshot_key SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.account_identities (`account_id` String, `display` String DEFAULT '', `verified` UInt8 DEFAULT 0, `email` String DEFAULT '', `web` String DEFAULT '', `twitter` String DEFAULT '', `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY account_id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_lock_snapshot_state (`snapshot_key` LowCardinality(String), `snapshot_id` String, `row_count` UInt32, `block_height` UInt32, `relay_height` UInt32, `source_checksum` String, `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) ORDER BY snapshot_key SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.account_lock_snapshots (`snapshot_id` String, `account_id` String, `asset_id` UInt32, `kind` LowCardinality(String), `source` LowCardinality(String), `amount` UInt256, `claimable` UInt256, `detail` String DEFAULT '', `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) PARTITION BY snapshot_id ORDER BY (snapshot_id, account_id, asset_id, kind, source) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.account_money_market_activity (`account_id` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `asset_address` String, `pool_address` Nullable(String), `amount` Nullable(String), `liquidated_collateral_amount` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account_id, block_height, event_index, event_name) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_swap_activity (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `signer` String, `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account, block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_swap_activity_queue (`queued_at` DateTime64(3), `block_height` UInt32, `event_index` UInt32, `extrinsic_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String, `ingested_at` DateTime) ENGINE = MergeTree PARTITION BY toYYYYMM(queued_at) ORDER BY (queued_at, block_height, event_index, ingested_at) TTL toDateTime(queued_at) + toIntervalDay(7) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.account_swap_activity_queue_seed (`id` UInt8, `seeded_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(seeded_at) ORDER BY id SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.account_swap_activity_queue_state (`id` UInt8, `queued_at` DateTime64(3), `block_height` UInt32, `event_index` UInt32, `ingested_at` DateTime, `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY id SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.account_tags (`label_id` String, `label_name` String, `color` String DEFAULT '', `note` String DEFAULT '', `icon` String DEFAULT '', `account_id` String, `deleted` UInt8 DEFAULT 0, `created_at` DateTime DEFAULT now(), `updated_at` DateTime64(3) DEFAULT now64(3)) ENGINE = ReplacingMergeTree(updated_at) ORDER BY (label_id, account_id) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_trade_volume (`account` String, `block_height` UInt32, `trade_key` UInt64, `volume_usd` Decimal(38, 12) DEFAULT 0, `net_in_usd` Decimal(38, 12) DEFAULT 0, `net_out_usd` Decimal(38, 12) DEFAULT 0, `trade_count` UInt32 DEFAULT 1, `computed_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(computed_at) PARTITION BY toYYYYMM(toDateTime(block_height * 12)) ORDER BY (account, block_height, trade_key) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.account_transfer_activity (`account` String, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `call_address` Nullable(String), `from_account` String, `to_account` String, `amount` String, `asset_id` UInt32) ENGINE = ReplacingMergeTree PARTITION BY toYYYYMM(block_timestamp) ORDER BY (account, block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.activity_histogram_events (`day` Date, `block_height` UInt32, `event_index` UInt32, `activity_index` UInt32, `event_name` LowCardinality(String), `asset_refs` Array(UInt32), `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(day) ORDER BY (block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.asset_swap_activity (`asset_id` UInt32, `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `asset_in` UInt32, `asset_out` UInt32, `amount_in` String, `amount_out` String) ENGINE = ReplacingMergeTree PARTITION BY toYYYYMM(block_timestamp) ORDER BY (asset_id, block_height, event_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.assets (`asset_id` UInt32, `symbol` String, `name` String, `decimals` UInt8, `parachain_id` Nullable(UInt32), `origin_ecosystem` Nullable(String), `origin_chain_id` Nullable(String), `origin_asset_id` Nullable(String)) ENGINE = ReplacingMergeTree ORDER BY asset_id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.atoken_reserve_map (`asset_address` String, `atoken` String, `vdebt` String, `pool_proxy` String, `market_key` LowCardinality(String), `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY (asset_address, atoken) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.atoken_scaled_anchor (`contract_address` String, `holder` String, `scaled_balance` Int256, `anchor_block` UInt32, `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY (contract_address, holder) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.atoken_scaled_deltas (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `leg_index` UInt8, `scaled_delta` Int256, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (holder, contract_address, block_height, event_index, leg_index) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.atoken_scaled_deltas_by_contract (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `leg_index` UInt8, `scaled_delta` Int256, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (contract_address, holder, block_height, event_index, leg_index) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.blocks (`block_height` UInt32, `block_timestamp` DateTime, `spec_version` UInt32) ENGINE = MergeTree PARTITION BY toYYYYMM(block_timestamp) ORDER BY block_height SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.daily_chain_identity_counts_v2 (`kind` LowCardinality(String), `day` Date, `identity_state` AggregateFunction(groupBitmap, UInt64)) ENGINE = AggregatingMergeTree PARTITION BY toYear(day) ORDER BY (kind, day) SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.dca_events (`id` UInt64, `event_name` LowCardinality(String), `block_height` UInt32, `block_timestamp` DateTime, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `who` String, `amount_in` String, `amount_out` String, `planned_block` UInt32) ENGINE = ReplacingMergeTree(block_height) ORDER BY (event_name, block_height, event_index, id) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.dca_schedules (`id` UInt64, `block_height` UInt32, `block_timestamp` DateTime, `extrinsic_index` Nullable(UInt32), `who` String, `asset_in` UInt32, `asset_out` UInt32, `direction` LowCardinality(String), `amount_per` String, `total_amount` String, `period` UInt32, `max_retries` UInt32) ENGINE = ReplacingMergeTree(block_height) ORDER BY id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.erc20_transfer_deltas (`contract_address` String, `holder` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `leg_index` UInt8, `balance_delta` Int256, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (holder, contract_address, block_height, event_index, leg_index) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.erc20_wallet_balances (`account_id` String, `asset_id` String, `total` String, `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY (asset_id, account_id) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.event_asset_refs (`asset_id` UInt32, `event_name` LowCardinality(String), `block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (asset_id, event_name, block_height, event_index) SETTINGS index_granularity = 2048;
CREATE TABLE IF NOT EXISTS price_data.farm_deposit_latest (`deposit_id` String, `position_id` AggregateFunction(argMax, String, UInt64)) ENGINE = AggregatingMergeTree ORDER BY deposit_id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.hdx_holder_lifetime (`account_id` String, `first_nonzero_state` AggregateFunction(min, DateTime), `last_nonzero_state` AggregateFunction(max, DateTime)) ENGINE = AggregatingMergeTree ORDER BY account_id SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.hsm_activity (`block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `event_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (block_height, event_index) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.incentive_claim_calls (`block_height` UInt32, `extrinsic_index` Nullable(UInt32), `call_address` String, `block_timestamp` DateTime, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (block_height, ifNull(extrinsic_index, 4294967295), call_address) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.incentive_reward_transfers (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `call_address` Nullable(String), `args_json` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (block_height, event_index) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.indexer_state (`id` String, `last_block` UInt32, `updated_at` DateTime64(3) DEFAULT now64(3)) ENGINE = ReplacingMergeTree(updated_at) ORDER BY id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.indexer_state_datetime64_backup (`id` String, `last_block` UInt32, `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY id SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.liquidity_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `who` String, `asset_id` UInt32, `amount` String, `amount_a` String, `asset_b` UInt32, `pool_account` String, `asset_refs` Array(UInt32), `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (block_height, event_index) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.lp_history_model_coverage (`model` LowCardinality(String), `range_start` UInt32, `range_end` UInt32, `source_high_watermark` UInt32, `status` Enum8('building' = 1, 'complete' = 2, 'failed' = 3), `row_count` UInt64, `checksum` String, `updated_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY (model, range_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.money_market_account_value_snapshot_state (`snapshot_key` LowCardinality(String), `snapshot_id` String, `source_holding_count` UInt32, `source_position_count` UInt32, `claim_count` UInt32, `source_checksum` String, `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) ORDER BY snapshot_key SETTINGS index_granularity = 64;
CREATE TABLE IF NOT EXISTS price_data.money_market_account_value_snapshots (`snapshot_id` String, `account_id` String, `holder` String, `pool_address` String, `market_key` LowCardinality(String), `reserve_present` UInt8, `asset_id` UInt32, `supplied` UInt256, `debt` UInt256, `total_collateral_base` UInt256, `total_debt_base` UInt256, `available_borrows_base` UInt256, `liquidation_threshold` UInt32, `ltv` UInt256, `health_factor` UInt256, `block_height` UInt32, `block_timestamp` DateTime, `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) PARTITION BY snapshot_id ORDER BY (snapshot_id, account_id, pool_address, reserve_present, asset_id) SETTINGS index_granularity = 1024;
CREATE TABLE IF NOT EXISTS price_data.money_market_reserve_indices (`pool_address` String, `reserve_address` String, `block_height` UInt32, `event_index` UInt32, `block_timestamp` DateTime, `liquidity_index` UInt256, `variable_borrow_index` UInt256, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (pool_address, reserve_address, block_height, event_index) SETTINGS index_granularity = 4096;
CREATE TABLE IF NOT EXISTS price_data.multisig_call_activity (`block_height` UInt32, `extrinsic_index` Nullable(UInt32), `call_address` String, `block_timestamp` DateTime, `call_name` LowCardinality(String), `args_json` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (block_height, ifNull(extrinsic_index, 4294967295), call_address) SETTINGS index_granularity = 256;
CREATE TABLE IF NOT EXISTS price_data.multisig_event_activity (`block_height` UInt32, `event_index` UInt32, `extrinsic_index` Nullable(UInt32), `block_timestamp` DateTime, `event_name` LowCardinality(String), `multisig` String, `actor` String, `call_hash` String, `ingested_at` DateTime) ENGINE = ReplacingMergeTree(ingested_at) PARTITION BY toYYYYMM(block_timestamp) ORDER BY (multisig, event_name, block_height, event_index) SETTINGS index_granularity = 256;
CREATE TABLE IF NOT EXISTS price_data.multisig_operation_activity (`multisig` String, `call_hash` String, `timepoint_height` UInt32, `timepoint_index` UInt32, `state` Enum8('pending' = 0, 'executed' = 1, 'cancelled' = 2), `threshold` UInt16, `signatories` UInt16, `approvals` UInt16, `actor` String, `anchor_block_height` UInt32, `anchor_extrinsic_index` UInt32, `anchor_timestamp` DateTime, `inner_call_name` LowCardinality(String) DEFAULT '', `inner_success` Nullable(UInt8), `run_id` UInt64, `ingested_at` DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(run_id) PARTITION BY tuple() ORDER BY (multisig, anchor_block_height, anchor_extrinsic_index, call_hash, timepoint_height, timepoint_index) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.nft_owner_latest (`collection` String, `item` String, `owner` AggregateFunction(argMax, String, UInt64)) ENGINE = AggregatingMergeTree ORDER BY (collection, item) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_15min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_1d (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_1h (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_1m (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_1w (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_30min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_4h (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.ohlc_5min (`asset_id` UInt32, `interval_start` DateTime, `open_state` AggregateFunction(argMin, Decimal(38, 12), DateTime), `high_state` AggregateFunction(max, Decimal(38, 12)), `low_state` AggregateFunction(min, Decimal(38, 12)), `close_state` AggregateFunction(argMax, Decimal(38, 12), DateTime), `volume_buy_state` AggregateFunction(sum, Decimal(38, 12)), `volume_sell_state` AggregateFunction(sum, Decimal(38, 12))) ENGINE = AggregatingMergeTree PARTITION BY toYYYYMM(interval_start) ORDER BY (asset_id, interval_start) SETTINGS index_granularity = 8192;
CREATE TABLE IF NOT EXISTS price_data.omnipool_account_claim_snapshot_state (`snapshot_key` LowCardinality(String), `snapshot_id` String, `source_position_count` UInt32, `claim_count` UInt32, `source_checksum` String, `computed_at` DateTime) ENGINE = ReplacingMergeTree(computed_at) ORDER BY snapshot_key SETTINGS index_granularity = 64;
